     1→import { TransactionType, PointsTransaction } from "./Models";
     2→
     3→type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     4→type TagSubType = 'DRIVE_THRU' | 'PEDAGIO' | 'ESTACIONAMENTO' | 'ABASTECIMENTO' | 'LAVA_RAPIDO';
     5→
     6→interface TransactionDetailField {
     7→  label?: string;
     8→  value?: string;
     9→}
    10→
    11→
    12→export const getTransactionGainType = (transaction: PointsTransaction): TransactionGainType => {
    13→  const provider = transaction.details?.provider?.toLowerCase() || '';
    14→  
    15→  if (provider.includes('cashback')) {
    16→    return 'CASHBACK';
    17→  }
    18→  
    19→  const icon = transaction.icon?.toLowerCase() || '';
    20→  const description = transaction.description?.toLowerCase() || '';
    21→  
    22→  const tagIndicators = ['tag', 'pedágio', 'pedagio', 'estacionamento', 'abastecimento', 'abastece', 'drive', 'lava', 'rápido'];
    23→  
    24→  const isTag = tagIndicators.some(indicator => 
    25→    icon.includes(indicator) || 
    26→    description.includes(indicator) || 
    27→    provider.includes(indicator)
    28→  );
    29→  
    30→  return isTag ? 'TAG' : 'CARD';
    31→};
    32→
    33→export const getTagSubType = (transaction: PointsTransaction): TagSubType | null => {
    34→  const description = transaction.description?.toUpperCase() || '';
    35→  const provider = transaction.details?.provider?.toUpperCase() || '';
    36→  const extraInfo = transaction.details?.extraInfo?.toUpperCase() || '';
    37→  const searchText = `${description} ${provider} ${extraInfo}`;
    38→  
    39→  if (searchText.includes('DRIVE') || searchText.includes('DRIVE-THRU') || searchText.includes('DRIVE THRU')) {
    40→    return 'DRIVE_THRU';
    41→  }
    42→  if (searchText.includes('PEDÁGIO') || searchText.includes('PEDAGIO')) {
    43→    return 'PEDAGIO';
    44→  }
    45→  if (searchText.includes('ESTACIONAMENTO')) {
    46→    return 'ESTACIONAMENTO';
    47→  }
    48→  if (searchText.includes('ABASTECIMENTO') || searchText.includes('ABASTECE')) {
    49→    return 'ABASTECIMENTO';
    50→  }
    51→  if (searchText.includes('LAVA') && searchText.includes('RÁPIDO')) {
    52→    return 'LAVA_RAPIDO';
    53→  }
    54→  
    55→  return null;
    56→};
    57→
    58→export const getDetailScreenTitle = (gainType: TransactionGainType, transactionType?: TransactionType): string => {
    59→  if (gainType === 'CASHBACK' && transactionType === 'RESCUE') {
    60→    return 'Detalhes de uso';
    61→  }
    62→  if (gainType === 'CASHBACK') {
