import {
  getTransactionGainType,
  getTagSubType,
  getDetailScreenTitle,
  getVehicleInfo,
  getPurchaseTypeLabel
} from '../../../src/screens/PointsDetail/utils';
import { PointsDetailProps } from '../../../src/screens/PointsDetail/Models';

describe('PointsDetail Utils', () => {
  describe('getTransactionGainType', () => {
    it('should return TAG when icon contains tag indicator', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-tag-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTransactionGainType(transaction)).toBe('TAG');
    });

    it('should return TAG when description contains tag indicator', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Pedágio test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTransactionGainType(transaction)).toBe('TAG');
    });

    it('should return TAG when provider contains tag indicator', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: 'estacionamento', extraInfo: '', fields: [] },
      };

      expect(getTransactionGainType(transaction)).toBe('TAG');
    });

    it('should return CASHBACK when provider contains cashback', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Cashback resgatado',
        type: 'DEBIT',
        amount: -500,
        currencyValue: 2996,
        icon: 'icon-tag',
        details: { provider: 'Cashback resgatado', extraInfo: 'Resgate de cashback em fatura', fields: [] },
      };

      expect(getTransactionGainType(transaction)).toBe('CASHBACK');
    });

    it('should return CASHBACK when provider contains cashback (case insensitive)', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'DEBIT',
        amount: -500,
        currencyValue: 2996,
        icon: 'icon-tag',
        details: { provider: 'CASHBACK RESGATADO', extraInfo: '', fields: [] },
      };

      expect(getTransactionGainType(transaction)).toBe('CASHBACK');
    });

    it('should return CARD when no tag indicators are found', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Regular purchase',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-card',
        details: { provider: 'store', extraInfo: '', fields: [] },
      };

      expect(getTransactionGainType(transaction)).toBe('CARD');
    });
  });

  describe('getTagSubType', () => {
    it('should return DRIVE_THRU when description contains drive', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Drive Thru',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTagSubType(transaction)).toBe('DRIVE_THRU');
    });

    it('should return PEDAGIO when description contains pedágio', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Pedágio',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTagSubType(transaction)).toBe('PEDAGIO');
    });

    it('should return ESTACIONAMENTO when description contains estacionamento', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Estacionamento',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTagSubType(transaction)).toBe('ESTACIONAMENTO');
    });

    it('should return ABASTECIMENTO when description contains abastecimento', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Abastecimento',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTagSubType(transaction)).toBe('ABASTECIMENTO');
    });

    it('should return LAVA_RAPIDO when description contains lava rápido', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Lava Rápido',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTagSubType(transaction)).toBe('LAVA_RAPIDO');
    });

    it('should return null when no tag subtype is found', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Regular purchase',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: { provider: '', extraInfo: '', fields: [] },
      };

      expect(getTagSubType(transaction)).toBeNull();
    });
  });

  describe('getDetailScreenTitle', () => {
    it('should return "Detalhes da compra" for CARD type', () => {
      expect(getDetailScreenTitle('CARD')).toBe('Detalhes da compra');
    });

    it('should return "Detalhes da pontuação" for TAG type', () => {
      expect(getDetailScreenTitle('TAG')).toBe('Detalhes da pontuação');
    });

    it('should return "Detalhes de uso" for CASHBACK type with DEBIT transaction', () => {
      expect(getDetailScreenTitle('CASHBACK', 'DEBIT')).toBe('Detalhes de uso');
    });

    it('should return "Detalhes do Cashback" for CASHBACK type with non-DEBIT transaction', () => {
      expect(getDetailScreenTitle('CASHBACK', 'RECEIVED')).toBe('Detalhes do Cashback');
    });

    it('should return "Detalhes do Cashback" for CASHBACK type when transaction type is not provided', () => {
      expect(getDetailScreenTitle('CASHBACK')).toBe('Detalhes do Cashback');
    });
  });

  describe('getVehicleInfo', () => {
    it('should return formatted string when marca, modelo and placa are present', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: {
          provider: '',
          extraInfo: '',
          fields: [
            { label: 'Marca', value: 'Toyota' },
            { label: 'Modelo', value: 'Corolla' },
            { label: 'Placa', value: 'ABC-1234' },
          ],
        },
      };

      expect(getVehicleInfo(transaction)).toBe('Toyota Corolla - ABC-1234');
    });

    it('should return placa only when marca and modelo are missing', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: {
          provider: '',
          extraInfo: '',
          fields: [
            { label: 'Placa', value: 'ABC-1234' },
          ],
        },
      };

      expect(getVehicleInfo(transaction)).toBe('ABC-1234');
    });

    it('should return null when no vehicle info is present', () => {
      const transaction: PointsDetailProps['transaction'] = {
        id: '1',
        date: '2024-01-15',
        description: 'Test',
        type: 'RECEIVED',
        amount: 100,
        currencyValue: 10,
        icon: 'icon-test',
        details: {
          provider: '',
          extraInfo: '',
          fields: [],
        },
      };

      expect(getVehicleInfo(transaction)).toBeNull();
    });
  });

  describe('getPurchaseTypeLabel', () => {
    it('should return correct label for DRIVE_THRU', () => {
      expect(getPurchaseTypeLabel('DRIVE_THRU')).toBe('Drive Thru');
    });

    it('should return correct label for PEDAGIO', () => {
      expect(getPurchaseTypeLabel('PEDAGIO')).toBe('Pedágio');
    });

    it('should return correct label for ESTACIONAMENTO', () => {
      expect(getPurchaseTypeLabel('ESTACIONAMENTO')).toBe('Estacionamento');
    });

    it('should return correct label for ABASTECIMENTO', () => {
      expect(getPurchaseTypeLabel('ABASTECIMENTO')).toBe('Abastecimento');
    });

    it('should return correct label for LAVA_RAPIDO', () => {
      expect(getPurchaseTypeLabel('LAVA_RAPIDO')).toBe('Lava Rápido');
    });

    it('should return empty string when tagSubType is null', () => {
      expect(getPurchaseTypeLabel(null)).toBe('');
    });
  });
});

